#include "PluginEditor.h"\n\n${plugin_name}AudioProcessorEditor::${plugin_name}AudioProcessorEditor(${plugin_name}AudioProcessor& p)\n    : AudioProcessorEditor(&p), audioProcessor(p)\n{\n    title.setText("${plugin_name}", juce::dontSendNotification);\n    title.setJustificationType(juce::Justification::centredLeft);\n    title.setFont(juce::FontOptions(24.0f, juce::Font::bold));\n    addAndMakeVisible(title);\n\n    subtitle.setText(juce::String("PAP ") + pap::getPapUiPluginType() + " • " + pap::getPapUiLayoutName(), juce::dontSendNotification);\n    subtitle.setJustificationType(juce::Justification::centredLeft);\n    addAndMakeVisible(subtitle);\n\n    runtimeBadge.setText("Runtime: Ready", juce::dontSendNotification);\n    runtimeBadge.setJustificationType(juce::Justification::centred);\n    runtimeBadge.setColour(juce::Label::backgroundColourId, juce::Colour(0xff1f2a37));\n    runtimeBadge.setColour(juce::Label::textColourId, juce::Colours::white);\n    addAndMakeVisible(runtimeBadge);\n\n    bridgeBadge.setText("CLI Bridge: Live", juce::dontSendNotification);\n    bridgeBadge.setJustificationType(juce::Justification::centred);\n    bridgeBadge.setColour(juce::Label::backgroundColourId, juce::Colour(0xff193c2f));\n    bridgeBadge.setColour(juce::Label::textColourId, juce::Colours::white);\n    addAndMakeVisible(bridgeBadge);\n\n    flowLabel.setText(audioProcessor.getPapSignalFlow(), juce::dontSendNotification);\n    flowLabel.setJustificationType(juce::Justification::centredLeft);\n    addAndMakeVisible(flowLabel);\n\n    checkpointLabel.setText(pap::getPapUiCheckpointHint(), juce::dontSendNotification);\n    checkpointLabel.setJustificationType(juce::Justification::centredLeft);\n    addAndMakeVisible(checkpointLabel);\n\n    buildPrimaryControls();\n    setSize(700, 420);\n}\n\nvoid ${plugin_name}AudioProcessorEditor::buildPrimaryControls()\n{\n    auto& apvts = audioProcessor.getValueTreeState();\n    const char* preferred[] = {"mix", "macro", "rate", "depth", "space", "drift", "attack", "release", "output", "voices"};\n    juce::StringArray ordered;\n    for (auto* id : preferred)\n        ordered.addIfNotAlreadyThere(id);\n\n    for (const auto& param : apvts.processor.getParameters())\n    {\n        if (auto* ranged = dynamic_cast<juce::RangedAudioParameter*>(param))\n            ordered.addIfNotAlreadyThere(ranged->paramID);\n    }\n\n    for (const auto& paramId : ordered)\n    {\n        if (auto* parameter = apvts.getParameter(paramId))\n        {\n            auto strip = std::make_unique<ParamStrip>();\n            strip->slider.setSliderStyle(juce::Slider::RotaryHorizontalVerticalDrag);\n            strip->slider.setTextBoxStyle(juce::Slider::TextBoxBelow, false, 72, 18);\n            strip->slider.setColour(juce::Slider::rotarySliderFillColourId, juce::Colour(0xff8b5cf6));\n            strip->slider.setColour(juce::Slider::thumbColourId, juce::Colour(0xfff8fafc));\n            strip->label.setText(parameter->getName(32), juce::dontSendNotification);\n            strip->label.setJustificationType(juce::Justification::centred);\n            strip->attachment = std::make_unique<SliderAttachment>(apvts, paramId, strip->slider);\n            addAndMakeVisible(strip->slider);\n            addAndMakeVisible(strip->label);\n            strips.push_back(std::move(strip));\n            if (strips.size() >= 6)\n                break;\n        }\n    }\n}\n\nvoid ${plugin_name}AudioProcessorEditor::paint(juce::Graphics& g)\n{\n    g.fillAll(juce::Colour(0xff0b1020));\n\n    auto bounds = getLocalBounds().reduced(14);\n    auto top = bounds.removeFromTop(92);\n    auto controlArea = bounds.removeFromTop(220);\n    auto footer = bounds;\n\n    g.setColour(juce::Colour(0xff111827));\n    g.fillRoundedRectangle(top.toFloat(), 18.0f);\n    g.fillRoundedRectangle(controlArea.toFloat(), 18.0f);\n    g.fillRoundedRectangle(footer.toFloat(), 18.0f);\n\n    g.setColour(juce::Colour(0x22ffffff));\n    g.drawRoundedRectangle(top.toFloat(), 18.0f, 1.0f);\n    g.drawRoundedRectangle(controlArea.toFloat(), 18.0f, 1.0f);\n    g.drawRoundedRectangle(footer.toFloat(), 18.0f, 1.0f);\n\n    g.setColour(juce::Colours::white);\n    g.setFont(juce::FontOptions(14.0f, juce::Font::bold));\n    g.drawText("Primary Controls", controlArea.withTrimmedTop(10).removeFromTop(24).withTrimmedLeft(16), juce::Justification::centredLeft);\n    g.drawText("Signal Flow", footer.withTrimmedTop(10).removeFromTop(24).withTrimmedLeft(16), juce::Justification::centredLeft);\n}\n\nvoid ${plugin_name}AudioProcessorEditor::resized()\n{\n    auto bounds = getLocalBounds().reduced(14);\n    auto top = bounds.removeFromTop(92).reduced(16, 12);\n    auto controls = bounds.removeFromTop(220).reduced(16, 16);\n    auto footer = bounds.reduced(16, 12);\n\n    auto titleArea = top.removeFromLeft(getWidth() - 260);\n    title.setBounds(titleArea.removeFromTop(34));\n    subtitle.setBounds(titleArea.removeFromTop(24));\n    checkpointLabel.setBounds(titleArea.removeFromTop(22));\n\n    auto badgeArea = top;\n    runtimeBadge.setBounds(badgeArea.removeFromTop(28));\n    badgeArea.removeFromTop(10);\n    bridgeBadge.setBounds(badgeArea.removeFromTop(28));\n\n    auto headerGap = controls.removeFromTop(28);\n    juce::ignoreUnused(headerGap);\n    auto row = controls;\n    const int count = (int) strips.size();\n    if (count > 0)\n    {\n        const int cellW = row.getWidth() / count;\n        for (int i = 0; i < count; ++i)\n        {\n            auto cell = row.removeFromLeft(cellW).reduced(6, 8);\n            strips[(size_t) i]->slider.setBounds(cell.removeFromTop(140));\n            strips[(size_t) i]->label.setBounds(cell.removeFromTop(24));\n        }\n    }\n\n    footer.removeFromTop(28);\n    flowLabel.setBounds(footer.removeFromTop(44));\n}\n